library(haven); library(dplyr); library(readr); w8 <- read_tsv('data/input/ns8_2015_derived.tab'); w9 <- read_tsv('data/input/ns9_2022_derived_variables.tab'); m <- full_join(w8, w9, by='NSID'); d <- m %>% select(NSID, W8DINCB, W9DINCB) %>% rename(inc25=W8DINCB, inc32=W9DINCB); d <- d %>% mutate(inc25=ifelse(is.na(inc25), -3, inc25), inc32=ifelse(is.na(inc32), -3, inc32)); dir.create('data/output', showWarnings=FALSE, recursive=TRUE); write_csv(d, 'data/output/cleaned_data.csv'); cat('Done')